```go
// Generated code usage
func (s *Service) GetUser(ctx context.Context, id int64) (*db.User, error) {
    queries := db.New(s.pool)
    user, err := queries.GetUser(ctx, id)
    if err != nil {
        return nil, fmt.Errorf("get user %d: %w", id, err)
    }
    return &user, nil
}

// Transactions
func (s *Service) CreateUserTx(ctx context.Context, email, name string) (*db.User, error) {
    tx, err := s.pool.Begin(ctx)
    if err != nil {
        return nil, err
    }
    defer tx.Rollback(ctx)

    queries := db.New(tx)
    user, err := queries.CreateUser(ctx, db.CreateUserParams{Email: email, Name: name})
    if err != nil {
        return nil, err
    }
    return &user, tx.Commit(ctx)
}
```

sqlc validates queries against your schema at code generation time. Typos in column names, wrong parameter types, and missing columns are all caught before runtime. Run `sqlc generate` after changing SQL files.

The `httptest` package creates mock HTTP requests and records responses without starting a real server.

```go
import (
    "net/http"
    "net/http/httptest"
    "strings"
    "testing"
)

func TestCreateUserHandler(t *testing.T) {
    // Create request
    body := strings.NewReader(`{"name":"Alice","email":"alice@example.com"}`)
    req := httptest.NewRequest("POST", "/api/users", body)
    req.Header.Set("Content-Type", "application/json")

    // Record response
    rec := httptest.NewRecorder()
    handleCreateUser(rec, req)

    // Assert
    if rec.Code != http.StatusCreated {
        t.Errorf("status = %d, want %d", rec.Code, http.StatusCreated)
    }

    var resp map[string]string
    json.NewDecoder(rec.Body).Decode(&resp)
    if resp["status"] != "created" {
        t.Errorf("body = %v, want status=created", resp)
    }
}

// Test against a full server (integration test)
func TestAPIIntegration(t *testing.T) {
    mux := http.NewServeMux()
    mux.HandleFunc("POST /api/users", handleCreateUser)
    mux.HandleFunc("GET /api/users/{id}", handleGetUser)

    srv := httptest.NewServer(mux)
    defer srv.Close()

    // Use srv.URL as base URL
    resp, err := http.Post(srv.URL+"/api/users",
        "application/json",
        strings.NewReader(`{"name":"Bob","email":"bob@test.com"}`),
    )
    if err != nil {
        t.Fatal(err)
    }
    defer resp.Body.Close()
    if resp.StatusCode != http.StatusCreated {
        t.Errorf("status = %d, want %d", resp.StatusCode, http.StatusCreated)
    }
}
```

`httptest.NewRecorder()` captures the response in memory for unit tests. `httptest.NewServer()` starts an actual HTTP server on a random port for integration tests. Both are in the standard library — no third-party packages needed.

A thread-safe in-memory cache using sync.Map with time-to-live expiration.

```go
type Cache[V any] struct {
    data sync.Map
    ttl  time.Duration
}

type entry[V any] struct {
    value     V
    expiresAt time.Time
}

func NewCache[V any](ttl time.Duration) *Cache[V] {
    c := &Cache[V]{ttl: ttl}
    // Background cleanup every TTL interval
    go func() {
        ticker := time.NewTicker(ttl)
        defer ticker.Stop()
        for range ticker.C {
            c.data.Range(func(key, value any) bool {
                e := value.(entry[V])
                if time.Now().After(e.expiresAt) {
                    c.data.Delete(key)
                }
                return true
            })
        }
    }()
    return c
}

func (c *Cache[V]) Set(key string, value V) {
    c.data.Store(key, entry[V]{
        value:     value,
        expiresAt: time.Now().Add(c.ttl),
    })
}

func (c *Cache[V]) Get(key string) (V, bool) {
    raw, ok := c.data.Load(key)
    if !ok {
        var zero V
        return zero, false
    }
    e := raw.(entry[V])
    if time.Now().After(e.expiresAt) {
        c.data.Delete(key)
        var zero V
        return zero, false
    }
    return e.value, true
}

func (c *Cache[V]) GetOrSet(key string, fn func() (V, error)) (V, error) {
    if val, ok := c.Get(key); ok {
        return val, nil
    }
    val, err := fn()
    if err != nil {
        var zero V
        return zero, err
    }
    c.Set(key, val)
    return val, nil
}

// Usage
cache := NewCache[User](5 * time.Minute)
cache.Set("user:123", user)
if u, ok := cache.Get("user:123"); ok {
    fmt.Println(u.Name)
}
```

For production, consider `github.com/dgraph-io/ristretto` (concurrent cache with admission policy) or `github.com/jellydator/ttlcache` (full-featured TTL cache). sync.Map is best for read-heavy workloads with stable keys.

Go 1.16's `//go:embed` directive bundles files into the compiled binary, eliminating external file dependencies.

```go
import "embed"

// Embed a single file as string
//go:embed config/defaults.yaml
var defaultConfig string

// Embed a single file as bytes
//go:embed migrations/001_init.sql
var initMigration []byte

// Embed entire directory tree
//go:embed static/*
var staticFiles embed.FS

// Embed multiple patterns
//go:embed templates/*.html templates/*.tmpl
var templateFiles embed.FS

func main() {
    // Serve embedded static files
    mux := http.NewServeMux()
    mux.Handle("GET /static/",
        http.StripPrefix("/static/",
            http.FileServer(http.FS(staticFiles))))

    // Parse embedded templates
    tmpl := template.Must(template.ParseFS(templateFiles, "templates/*.html"))
    tmpl.ExecuteTemplate(w, "index.html", data)

    // Read embedded file
    content, err := staticFiles.ReadFile("static/index.html")
    if err != nil {
        log.Fatal(err)
    }

    // Walk embedded directory
    fs.WalkDir(staticFiles, ".", func(path string, d fs.DirEntry, err error) error {
        fmt.Println(path)
        return nil
    })
}
```

Embed rules: the directive must be immediately above the variable. Only exported and unexported package-level variables are allowed (not local variables). Patterns are relative to the package directory. Hidden files (dot-prefix) and `_` prefix files are excluded by default — use `all:` prefix to include them (`//go:embed all:static`).

Go provides three main synchronization primitives at different performance points.

```go
import (
    "sync"
    "sync/atomic"
)

// sync.Mutex — exclusive access, simplest
type Counter struct {
    mu    sync.Mutex
    count int
}
func (c *Counter) Increment() {
    c.mu.Lock()
    defer c.mu.Unlock()
    c.count++
}
func (c *Counter) Get() int {
    c.mu.Lock()
    defer c.mu.Unlock()
    return c.count
}

// sync.RWMutex — multiple readers OR one writer
type Cache struct {
    mu   sync.RWMutex
    data map[string]string
}
func (c *Cache) Get(key string) string {
    c.mu.RLock()         // multiple goroutines can read simultaneously
    defer c.mu.RUnlock()
    return c.data[key]
}
func (c *Cache) Set(key, val string) {
    c.mu.Lock()          // exclusive write access
    defer c.mu.Unlock()
    c.data[key] = val
}

// atomic — lock-free, fastest for simple operations
var counter atomic.Int64
counter.Add(1)
val := counter.Load()
counter.Store(0)

// atomic.Value for larger types
var config atomic.Value
config.Store(Config{Debug: true})
cfg := config.Load().(Config)
```

| Primitive | Use case | Readers block? | Performance |
|-----------|----------|---------------|-------------|
| Mutex | Any shared state | Yes, all block | Baseline |
| RWMutex | Read-heavy workloads | No, readers concurrent | Better for reads |
| atomic | Counters, flags, config | No blocking | Fastest |

Rule of thumb: use `atomic` for simple values (counters, booleans, config swaps). Use `RWMutex` when reads vastly outnumber writes (10:1+). Use `Mutex` as the default when unsure.

This panic occurs when calling `.unwrap()` on an `Option::None` or `.unwrap()` on a `Result::Err`. It's Rust's equivalent of a null pointer exception.

```rust
// PANIC: called `Option::unwrap()` on a `None` value
let v: Vec<i32> = vec![];
let first = v.first().unwrap(); // None — panics!

// PANIC: called `Result::unwrap()` on an `Err` value
let content = std::fs::read_to_string("missing.txt").unwrap();

// FIX: handle the None/Err case
let first = v.first().unwrap_or(&0);
let first = v.first().copied().unwrap_or_default();

// FIX: pattern match
match v.first() {
    Some(val) => println!("first: {}", val),
    None => println!("empty"),
}

// FIX: if let
if let Some(val) = v.first() {
    println!("first: {}", val);
}

// FIX: propagate with ?
fn read_config() -> Result<Config, Error> {
    let content = std::fs::read_to_string("config.toml")?; // returns Err if fails
    Ok(toml::from_str(&content)?)
}
```

Use `.unwrap()` only in tests, examples, or when you've logically proven the value exists. In production code, use `?`, `.unwrap_or()`, `.unwrap_or_default()`, `.unwrap_or_else()`, or pattern matching. For a better panic message, use `.expect("descriptive message")` instead of `.unwrap()`.

This error occurs when you create a temporary value and try to borrow it in a way that outlives the temporary.

```rust
// ERROR: temporary value dropped while borrowed
fn get_name() -> &str {
    let name = String::from("Alice");
    &name // ERROR: name is dropped at end of function
}

// ERROR: common with format!()
fn get_greeting(name: &str) -> &str {
    let s = format!("Hello, {}!", name);
    &s // ERROR: s is temporary, dropped here
}

// FIX: return owned value
fn get_name() -> String {
    String::from("Alice")
}

fn get_greeting(name: &str) -> String {
    format!("Hello, {}!", name)
}

// ERROR: temporary in let binding
let s: &str = &String::from("hello"); // ERROR in some contexts
// FIX: bind the owned value first
let owned = String::from("hello");
let s: &str = &owned; // OK: owned lives long enough

// ERROR: temporary in match
match &String::from("hello") { // temporary dropped after match
    s => println!("{}", s),    // sometimes works, sometimes doesn't
}
```

The rule: a reference cannot outlive the value it points to. If the value is a temporary (created inline), it's dropped at the end of the statement. Bind temporary values to a named variable to extend their lifetime, or return owned types instead of references.

Go panics when you slice beyond the current length (for reads) or capacity (for extending). This often happens when processing input of unexpected size.

```go
// PANIC: slice bounds out of range [:5] with length 3
s := []int{1, 2, 3}
sub := s[:5] // panic!

// PANIC: runtime error when processing API response
func getFirstN(items []string, n int) []string {
    return items[:n] // panics if len(items) < n
}

// FIX: bounds check
func getFirstN(items []string, n int) []string {
    if n > len(items) {
        n = len(items)
    }
    return items[:n]
}

// Using min() (Go 1.21+)
func getFirstN(items []string, n int) []string {
    return items[:min(n, len(items))]
}

// Common pattern: safe substring
func truncate(s string, maxLen int) string {
    if len(s) <= maxLen {
        return s
    }
    // Be careful with Unicode!
    runes := []rune(s)
    if len(runes) <= maxLen {
        return s
    }
    return string(runes[:maxLen]) + "..."
}
```

Remember: `s[low:high]` panics if `high > len(s)` for reads. For appending to sub-slices, the limit is capacity, not length. Always validate indices from external input before slicing.

Async methods in traits were not directly supported until Rust 1.75. Older code uses the `async-trait` crate, which has performance implications.

```rust
// Before Rust 1.75: use async-trait crate
use async_trait::async_trait;

#[async_trait]
trait Repository {
    async fn find_by_id(&self, id: i64) -> Result<User, Error>;
}

#[async_trait]
impl Repository for PostgresRepo {
    async fn find_by_id(&self, id: i64) -> Result<User, Error> {
        sqlx::query_as!(User, "SELECT * FROM users WHERE id = $1", id)
            .fetch_one(&self.pool)
            .await
    }
}
// async-trait uses Box<dyn Future> — heap allocation per call

// Rust 1.75+: native async trait methods (RPITIT)
trait Repository {
    fn find_by_id(&self, id: i64) -> impl Future<Output = Result<User, Error>> + Send;
}

// Rust 1.80+: direct async fn in trait
trait Repository {
    async fn find_by_id(&self, id: i64) -> Result<User, Error>;
}

impl Repository for PostgresRepo {
    async fn find_by_id(&self, id: i64) -> Result<User, Error> {
        // ... zero-cost, no Box allocation
    }
}
```

Rust 1.75+ RPITIT (return-position impl Trait in traits) eliminates the need for `async-trait` in most cases. The native version avoids heap allocation. However, native async trait methods are not object-safe — you still need `async-trait` if you need `dyn Trait`.

Implementing `From<T>` automatically gives you `Into<U>`. Implementing `Into` directly is almost never correct.

```rust
struct Celsius(f64);
struct Fahrenheit(f64);

// Implement From — standard convention
impl From<Celsius> for Fahrenheit {
    fn from(c: Celsius) -> Self {
        Fahrenheit(c.0 * 9.0 / 5.0 + 32.0)
    }
}

// You get Into for free
let c = Celsius(100.0);
let f: Fahrenheit = c.into();       // works via blanket impl
let f = Fahrenheit::from(Celsius(100.0)); // also works

// Use Into in function bounds for flexibility
fn set_temperature(temp: impl Into<Fahrenheit>) {
    let f: Fahrenheit = temp.into();
}
set_temperature(Celsius(37.0));    // auto-converts
set_temperature(Fahrenheit(98.6)); // works directly (From<Self>)

// GOTCHA: From<T> for T is always implemented (identity)
// So Fahrenheit::from(Fahrenheit(98.6)) works too

// TryFrom for fallible conversions
impl TryFrom<&str> for Celsius {
    type Error = ParseFloatError;
    fn try_from(s: &str) -> Result<Self, Self::Error> {
        Ok(Celsius(s.parse()?))
    }
}
let c: Celsius = "37.5".try_into()?;
```

Always implement `From`, never `Into` directly. The standard library provides a blanket `impl<T, U> Into<U> for T where U: From<T>`. For conversions that can fail, implement `TryFrom` instead of `From`.

Deferred function arguments are evaluated at the defer statement, not when the deferred function executes. This catches people who expect lazy evaluation.

```go
// SURPRISE: prints 0, not 1
func main() {
    x := 0
    defer fmt.Println(x) // x is evaluated NOW (x = 0)
    x = 1
}
// Output: 0

// FIX 1: use a closure to capture the variable
func main() {
    x := 0
    defer func() {
        fmt.Println(x) // closure captures x by reference
    }()
    x = 1
}
// Output: 1

// FIX 2: use named return values
func getResult() (result int) {
    defer func() {
        result *= 2 // modifies named return value
    }()
    return 5
}
// Returns 10, not 5

// Common mistake: logging execution time
start := time.Now()
defer fmt.Println(time.Since(start)) // evaluated NOW — always ~0
// FIX:
defer func() {
    fmt.Println(time.Since(start)) // evaluated at function exit
}()
```

This behavior is specified in the Go spec: "the function value and parameters are evaluated as usual" at the defer statement. Only the execution is deferred. Wrap in a closure for late-binding behavior.

Go strings are immutable byte slices. `len()` returns bytes, not Unicode characters. Indexing gives you bytes, not runes.

```go
s := "Hello, 世界" // Chinese characters are multi-byte UTF-8

fmt.Println(len(s))        // 13 bytes, NOT 9 characters
fmt.Println(s[7])          // 228 (a byte), NOT '世'
fmt.Println(s[7:10])       // "世" (3 bytes for this character)

// Iterate by rune (character)
for i, r := range s {
    fmt.Printf("%d: %c (%d bytes)\n", i, r, utf8.RuneLen(r))
}
// 0: H (1), 1: e (1), ..., 7: 世 (3), 10: 界 (3)

// Count characters, not bytes
charCount := utf8.RuneCountInString(s) // 9

// Safe substring by character
runes := []rune(s)
first5 := string(runes[:5]) // "Hello" — correct
// s[:5] also happens to work here, but only because first 5 chars are ASCII

// GOTCHA: truncating mid-character produces invalid UTF-8
bad := s[:8] // cuts '世' in the middle — invalid UTF-8
```

Always use `[]rune` conversion or `utf8.RuneCountInString()` when working with Unicode. The `range` loop over a string already iterates by rune. For heavy string processing, the `strings` and `unicode/utf8` packages handle multi-byte characters correctly.

Rust drops struct fields in the order they are declared, and local variables in reverse order of declaration. This matters when fields reference each other.

```rust
struct Connection {
    pool: Pool,      // dropped first
    session: Session, // dropped second
}
// If session depends on pool, this is wrong!
// session is dropped AFTER pool, but session might need pool during drop

// FIX: reorder fields so dependencies are dropped first
struct Connection {
    session: Session, // dropped first (depends on pool)
    pool: Pool,       // dropped second
}

// Local variables drop in reverse declaration order
fn example() {
    let a = String::from("first");  // dropped last
    let b = String::from("second"); // dropped first
}

// ManuallyDrop for explicit control
use std::mem::ManuallyDrop;
struct Wrapper {
    // Won't be dropped automatically — you must drop it manually
    inner: ManuallyDrop<Resource>,
}

impl Drop for Wrapper {
    fn drop(&mut self) {
        // Explicit cleanup order
        println!("cleaning up");
        unsafe { ManuallyDrop::drop(&mut self.inner); }
    }
}
```

Most of the time drop order doesn't matter. But for types with `Drop` implementations that interact (database connections, file handles, lock guards), field declaration order determines destruction order. Use `ManuallyDrop` or `Option::take()` for explicit control.

Rust enums with data model state machines naturally. Each variant carries only the data relevant to that state, and pattern matching ensures all states are handled.

```rust
#[derive(Debug)]
enum ConnectionState {
    Disconnected,
    Connecting { attempt: u32, started_at: Instant },
    Connected { session_id: String, latency_ms: u64 },
    Reconnecting { previous_session: String, attempt: u32 },
}

impl ConnectionState {
    fn handle_event(self, event: Event) -> Self {
        match (self, event) {
            (ConnectionState::Disconnected, Event::Connect) => {
                ConnectionState::Connecting {
                    attempt: 1,
                    started_at: Instant::now(),
                }
            }
            (ConnectionState::Connecting { attempt, .. }, Event::Success(session_id)) => {
                ConnectionState::Connected {
                    session_id,
                    latency_ms: 0,
                }
            }
            (ConnectionState::Connecting { attempt, .. }, Event::Failure) if attempt < 3 => {
                ConnectionState::Connecting {
                    attempt: attempt + 1,
                    started_at: Instant::now(),
                }
            }
            (ConnectionState::Connecting { .. }, Event::Failure) => {
                ConnectionState::Disconnected
            }
            (ConnectionState::Connected { session_id, .. }, Event::Disconnect) => {
                ConnectionState::Reconnecting {
                    previous_session: session_id,
                    attempt: 1,
                }
            }
            (state, _) => state, // ignore invalid transitions
        }
    }
}
```

This pattern is superior to boolean flags or integer state codes because: invalid states are unrepresentable, each state carries only its relevant data, and the compiler forces you to handle all state/event combinations. The `(self, event)` tuple match makes transitions explicit and readable.

Reqwest is the standard HTTP client for Rust. Production usage needs timeouts, retries, and connection pooling.

```rust
use reqwest::{Client, StatusCode};
use serde::{Deserialize, Serialize};
use std::time::Duration;

#[derive(Deserialize, Debug)]
struct ApiResponse {
    data: Vec<Item>,
    total: usize,
}

// Create a reusable client (connection pooling)
fn build_client() -> Client {
    Client::builder()
        .timeout(Duration::from_secs(10))
        .connect_timeout(Duration::from_secs(5))
        .pool_max_idle_per_host(10)
        .default_headers({
            let mut h = reqwest::header::HeaderMap::new();
            h.insert("User-Agent", "my-app/1.0".parse().unwrap());
            h
        })
        .build()
        .expect("failed to build HTTP client")
}

async fn fetch_with_retry(client: &Client, url: &str, max_retries: u32) -> anyhow::Result<ApiResponse> {
    let mut last_err = None;
    for attempt in 0..=max_retries {
        if attempt > 0 {
            tokio::time::sleep(Duration::from_millis(100 * 2u64.pow(attempt - 1))).await;
        }
        match client.get(url).send().await {
            Ok(resp) if resp.status().is_success() => {
                return resp.json::<ApiResponse>().await.map_err(Into::into);
            }
            Ok(resp) if resp.status() == StatusCode::TOO_MANY_REQUESTS => {
                last_err = Some(anyhow::anyhow!("rate limited"));
                continue;
            }
            Ok(resp) => {
                return Err(anyhow::anyhow!("HTTP {}", resp.status()));
            }
            Err(e) if e.is_timeout() || e.is_connect() => {
                last_err = Some(e.into());
                continue;
            }
            Err(e) => return Err(e.into()),
        }
    }
    Err(last_err.unwrap_or_else(|| anyhow::anyhow!("max retries exceeded")))
}
```

Always reuse the `Client` instance — it manages a connection pool internally. Creating a new `Client` per request wastes connections. Use exponential backoff for retries. Only retry on transient errors (timeouts, 429, 503), not on 4xx client errors.

Context values carry request-scoped data through the handler chain. Use custom key types to avoid collisions.

```go
// Define typed context keys — never use strings or built-in types
type contextKey string

const (
    userKey    contextKey = "user"
    requestKey contextKey = "requestID"
)

// Middleware sets values
func AuthMiddleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        token := r.Header.Get("Authorization")
        user, err := validateToken(strings.TrimPrefix(token, "Bearer "))
        if err != nil {
            http.Error(w, "unauthorized", 401)
            return
        }
        ctx := context.WithValue(r.Context(), userKey, user)
        next.ServeHTTP(w, r.WithContext(ctx))
    })
}

func RequestIDMiddleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        id := r.Header.Get("X-Request-ID")
        if id == "" {
            id = uuid.NewString()
        }
        ctx := context.WithValue(r.Context(), requestKey, id)
        w.Header().Set("X-Request-ID", id)
        next.ServeHTTP(w, r.WithContext(ctx))
    })
}

// Type-safe helper functions
func UserFromContext(ctx context.Context) (*User, bool) {
    user, ok := ctx.Value(userKey).(*User)
    return user, ok
}

func RequestIDFromContext(ctx context.Context) string {
    if id, ok := ctx.Value(requestKey).(string); ok {
        return id
    }
    return "unknown"
}

// Handler reads values
func handleProfile(w http.ResponseWriter, r *http.Request) {
    user, ok := UserFromContext(r.Context())
    if !ok {
        http.Error(w, "no user in context", 500)
        return
    }
    slog.Info("profile viewed",
        "user", user.Email,
        "request_id", RequestIDFromContext(r.Context()),
    )
}
```

Never use context values for passing function parameters — only for request-scoped, cross-cutting data (user info, trace IDs, logger). Use a custom unexported type for keys to prevent collisions with other packages. Always provide helper functions for type-safe retrieval.

The turbofish operator (`::<>`) is required when the compiler cannot determine a generic type from context. This is most common with `collect()` and `parse()`.

```rust
// ERROR: type annotations needed
let numbers = "1,2,3".split(',').collect(); // collect into what?

// FIX: turbofish on collect
let numbers = "1,2,3".split(',').collect::<Vec<&str>>();

// FIX: type annotation on binding
let numbers: Vec<&str> = "1,2,3".split(',').collect();

// Double turbofish for nested generics
let parsed: Result<Vec<i32>, _> = "1,2,3"
    .split(',')
    .map(|s| s.parse::<i32>()) // turbofish on parse
    .collect();                  // type inferred from binding

// Turbofish on function calls
let default = <Vec<i32>>::default(); // default for Vec<i32>
let default = Vec::<i32>::new();      // equivalent

// HashMap needs both key and value types
use std::collections::HashMap;
let map = vec![("a", 1), ("b", 2)]
    .into_iter()
    .collect::<HashMap<&str, i32>>();

// Use _ to let compiler infer partial types
let map: HashMap<_, _> = vec![("a", 1)].into_iter().collect();
```

The turbofish name comes from `::<>` looking like a fish. It's needed because Rust resolves generics through local type inference — if the return type doesn't flow backward to resolve the generic, you must specify it explicitly.

Embedding a struct promotes all its methods to the outer struct. This can accidentally make a type satisfy an interface you didn't intend.

```go
type Logger struct{}
func (l Logger) Write(p []byte) (int, error) {
    fmt.Print(string(p))
    return len(p), nil
}

type MyService struct {
    Logger // embedded — promotes Write method
    // ...
}

// SURPRISE: MyService now satisfies io.Writer!
var w io.Writer = MyService{} // compiles!

// This can cause bugs when a function accepts io.Writer
// and your service gets passed where a Writer was expected

// Also: embedded mutex promotes Lock/Unlock to the outer type
type Cache struct {
    sync.Mutex // promotes Lock() and Unlock() as PUBLIC methods!
    data map[string]int
}
c := Cache{}
c.Lock()   // callers can lock your cache externally!
c.Unlock()

// FIX: use a named field instead of embedding
type Cache struct {
    mu   sync.Mutex // unexported named field — Lock/Unlock stay private
    data map[string]int
}
```

Embed for intentional promotion (extending behavior). Use named fields when you want the embedded type's methods to stay internal. Be especially careful embedding `sync.Mutex` — always use a named unexported field `mu sync.Mutex` to keep locking private.

Rust's orphan rule prevents implementing a foreign trait for a foreign type. This ensures coherence — each trait implementation is unique.

```rust
// ERROR: conflicting implementations
// You cannot implement Display for Vec<T> — both are from std
impl std::fmt::Display for Vec<i32> {
    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        write!(f, "{:?}", self)
    }
}
// error: only traits defined in the current crate can be implemented for types defined outside

// FIX: newtype wrapper
struct MyVec(Vec<i32>);

impl std::fmt::Display for MyVec {
    fn fmt(&self, f: &mut std::fmt::Formatter) -> std::fmt::Result {
        let items: Vec<String> = self.0.iter().map(|x| x.to_string()).collect();
        write!(f, "[{}]", items.join(", "))
    }
}

// The rule: at least one of {trait, type} must be local to your crate
// OK: local trait + foreign type
trait MyTrait {}
impl MyTrait for Vec<i32> {} // fine

// OK: foreign trait + local type
struct MyType;
impl std::fmt::Display for MyType {} // fine

// NOT OK: foreign trait + foreign type
// impl std::fmt::Display for Vec<i32> {} // error
```

The orphan rule prevents two crates from creating conflicting implementations of the same trait for the same type. The newtype pattern is the standard workaround. Use `derive_more` crate to auto-derive forwarding implementations for newtypes.

gRPC uses interceptors (the equivalent of HTTP middleware) for cross-cutting concerns like logging, auth, and metrics.

```go
import (
    "google.golang.org/grpc"
    "google.golang.org/grpc/codes"
    "google.golang.org/grpc/status"
)

// Unary interceptor (request-response)
func LoggingInterceptor(
    ctx context.Context,
    req any,
    info *grpc.UnaryServerInfo,
    handler grpc.UnaryHandler,
) (any, error) {
    start := time.Now()
    resp, err := handler(ctx, req)
    duration := time.Since(start)

    code := codes.OK
    if err != nil {
        code = status.Code(err)
    }
    slog.Info("grpc request",
        "method", info.FullMethod,
        "code", code,
        "duration", duration,
    )
    return resp, err
}

// Auth interceptor
func AuthInterceptor(
    ctx context.Context,
    req any,
    info *grpc.UnaryServerInfo,
    handler grpc.UnaryHandler,
) (any, error) {
    md, ok := metadata.FromIncomingContext(ctx)
    if !ok {
        return nil, status.Error(codes.Unauthenticated, "no metadata")
    }
    tokens := md.Get("authorization")
    if len(tokens) == 0 {
        return nil, status.Error(codes.Unauthenticated, "no token")
    }
    user, err := validateToken(tokens[0])
    if err != nil {
        return nil, status.Error(codes.Unauthenticated, "invalid token")
    }
    ctx = context.WithValue(ctx, userKey, user)
    return handler(ctx, req)
}

// Chain interceptors
srv := grpc.NewServer(
    grpc.ChainUnaryInterceptor(
        LoggingInterceptor,
        AuthInterceptor,
    ),
)
```

gRPC interceptors follow the same pattern as HTTP middleware: wrap the handler, add behavior before/after. Use `ChainUnaryInterceptor` for request-response RPCs and `ChainStreamInterceptor` for streaming RPCs. The `grpc-middleware` package provides pre-built interceptors for common needs.

Go's testing philosophy emphasizes the standard library, but assertion libraries reduce boilerplate.

```go
// Standard library — verbose but no dependencies
func TestAdd(t *testing.T) {
    got := Add(2, 3)
    want := 5
    if got != want {
        t.Errorf("Add(2, 3) = %d, want %d", got, want)
    }
}

// testify — most popular, rich assertions
import "github.com/stretchr/testify/assert"
func TestAdd(t *testing.T) {
    assert.Equal(t, 5, Add(2, 3))
    assert.NotNil(t, result)
    assert.Contains(t, "hello world", "hello")
    assert.Len(t, items, 3)
    assert.ErrorIs(t, err, ErrNotFound)
}

// testify/require — stops test on first failure
import "github.com/stretchr/testify/require"
func TestWorkflow(t *testing.T) {
    user, err := createUser("alice")
    require.NoError(t, err)  // stops here if error
    require.NotNil(t, user)
    assert.Equal(t, "alice", user.Name) // continues on failure
}

// testify/mock — interface mocking
type MockDB struct { mock.Mock }
func (m *MockDB) GetUser(id int) (*User, error) {
    args := m.Called(id)
    return args.Get(0).(*User), args.Error(1)
}
```

| Feature | stdlib | testify | is |
|---------|--------|---------|----|
| Dependencies | None | ~5 deps | 0 deps |
| Assertion style | Manual if/t.Error | assert.Equal | is.Equal |
| Mocking | Manual structs | mock.Mock | Not included |
| Adoption | Universal | Most popular | Minimal |

Many Go teams use stdlib for simple tests and testify for complex assertions. The `require` package (fail-fast) is useful for setup steps where subsequent assertions would be meaningless.

Rust automatically dereferences through `Deref` trait implementations, which can hide what's actually happening.

```rust
// String -> &str via Deref
fn takes_str(s: &str) { println!("{}", s); }

let s = String::from("hello");
takes_str(&s); // &String automatically coerced to &str via Deref

// Multiple levels of Deref
let boxed: Box<String> = Box::new(String::from("hello"));
takes_str(&boxed); // Box<String> -> String -> &str

// Vec<T> -> &[T] via Deref
fn takes_slice(s: &[i32]) { println!("{:?}", s); }
let v = vec![1, 2, 3];
takes_slice(&v); // &Vec<i32> coerced to &[i32]

// GOTCHA: method resolution through Deref can be surprising
let s = String::from("hello");
s.len(); // calls str::len() through Deref, not String::len()

// GOTCHA: Deref coercion only works for references
let s = String::from("hello");
// let x: &str = s; // ERROR — not a reference coercion
let x: &str = &s;   // OK — Deref coercion through &
```

Deref coercion makes Rust ergonomic — you can pass `&String` where `&str` is expected, `&Vec<T>` where `&[T]` is expected. But it can make method resolution confusing when both the wrapper and inner type have methods with the same name. Use explicit `(*val)` or `val.as_str()` when clarity matters.

Go channels can be directional — send-only or receive-only. Passing the wrong direction to a function causes a compile error.

```go
// Bidirectional channel
ch := make(chan int)

// Send-only channel
func producer(ch chan<- int) {
    ch <- 42
    // val := <-ch // ERROR: cannot receive from send-only channel
}

// Receive-only channel
func consumer(ch <-chan int) {
    val := <-ch
    // ch <- 1 // ERROR: cannot send to receive-only channel
}

// Bidirectional converts to directional implicitly
ch := make(chan int)
go producer(ch) // chan int -> chan<- int: OK
go consumer(ch) // chan int -> <-chan int: OK

// But directional cannot convert back to bidirectional
func broken(sendOnly chan<- int) {
    // ch := (chan int)(sendOnly) // ERROR: cannot convert
}

// Common pattern: function returns receive-only channel
func generate(nums ...int) <-chan int {
    out := make(chan int)
    go func() {
        defer close(out)
        for _, n := range nums {
            out <- n
        }
    }()
    return out // returns as receive-only
}

for val := range generate(1, 2, 3) {
    fmt.Println(val)
}
```

Directional channels enforce data flow at compile time. Return `<-chan T` from producer functions and accept `chan<- T` in consumer functions. This makes the API self-documenting and prevents misuse.

Failing to close `resp.Body` leaks TCP connections. The connection cannot be reused by the HTTP client pool, eventually exhausting file descriptors.

```go
// BUG: body not closed on early return
resp, err := http.Get(url)
if err != nil {
    return err
}
if resp.StatusCode != 200 {
    return fmt.Errorf("status %d", resp.StatusCode)
    // LEAKED: resp.Body not closed!
}
defer resp.Body.Close()

// FIX: always defer close immediately after error check
resp, err := http.Get(url)
if err != nil {
    return err
}
defer resp.Body.Close() // close regardless of status code

if resp.StatusCode != 200 {
    body, _ := io.ReadAll(resp.Body)
    return fmt.Errorf("status %d: %s", resp.StatusCode, body)
}

// ALSO: must drain the body for connection reuse
// Even if you don't need the body:
defer func() {
    io.Copy(io.Discard, resp.Body) // drain remaining bytes
    resp.Body.Close()
}()

// Or use the helper pattern:
func drainAndClose(body io.ReadCloser) {
    io.Copy(io.Discard, body)
    body.Close()
}
defer drainAndClose(resp.Body)
```

Three rules: (1) always close the body, (2) close it even on non-200 status codes, (3) drain unread bytes before closing so the connection returns to the pool. Unclosed bodies manifest as "too many open files" or connection timeout errors under load.

When you know all concrete types at compile time, an enum dispatch avoids the heap allocation and vtable lookup of `Box<dyn Trait>`.

```rust
// Dynamic dispatch — heap allocation, vtable
trait Shape {
    fn area(&self) -> f64;
}

struct Circle { radius: f64 }
struct Rectangle { width: f64, height: f64 }

impl Shape for Circle {
    fn area(&self) -> f64 { std::f64::consts::PI * self.radius * self.radius }
}
impl Shape for Rectangle {
    fn area(&self) -> f64 { self.width * self.height }
}

// With dyn — heap allocated
let shapes: Vec<Box<dyn Shape>> = vec![
    Box::new(Circle { radius: 5.0 }),
    Box::new(Rectangle { width: 3.0, height: 4.0 }),
];

// Enum dispatch — stack allocated, no vtable
enum AnyShape {
    Circle(Circle),
    Rectangle(Rectangle),
}

impl AnyShape {
    fn area(&self) -> f64 {
        match self {
            AnyShape::Circle(c) => c.area(),
            AnyShape::Rectangle(r) => r.area(),
        }
    }
}

let shapes: Vec<AnyShape> = vec![
    AnyShape::Circle(Circle { radius: 5.0 }),
    AnyShape::Rectangle(Rectangle { width: 3.0, height: 4.0 }),
];
// No heap allocation per element, better cache locality
```

Enum dispatch is faster (no indirection, better cache locality) but requires knowing all types at compile time. Use `dyn Trait` when types are open-ended (plugins, callbacks from user code). Use enum dispatch for closed type sets (AST nodes, protocol messages).

Unlike slices, which work with nil (append to nil slice is fine), maps must be initialized before writing to them.

```go
// PANIC: assignment to entry in nil map
var m map[string]int
m["key"] = 1 // panic!

// Reading from nil map is safe (returns zero value)
var m map[string]int
v := m["key"]     // v = 0, no panic
_, ok := m["key"] // ok = false, no panic

// MUST initialize before writing
m := make(map[string]int)
m["key"] = 1 // fine

// Or with literal
m := map[string]int{"key": 1}

// Common bug in struct initialization
type Stats struct {
    Counts map[string]int
}

s := Stats{} // Counts is nil!
s.Counts["page"] = 1 // PANIC

// FIX: constructor
func NewStats() *Stats {
    return &Stats{
        Counts: make(map[string]int),
    }
}

// Or initialize lazily
func (s *Stats) Increment(key string) {
    if s.Counts == nil {
        s.Counts = make(map[string]int)
    }
    s.Counts[key]++
}
```

Always initialize maps in constructors or before first write. This is one of Go's most common nil panics, especially with nested structs containing map fields. The asymmetry (nil read is safe, nil write panics) is by design — reads return the zero value, but writes need allocated memory.
